var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제7 방위선, 거점 기지","JPN":"人類統合防衛軍第7防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 7th Defense Line","TWN":"人類共同保衛軍 第七防線基地"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안 돼. 이럴 수는 없어, 이럴 수는.","JPN":"そんな、嘘。こんなの嘘よ。","ENG":"No. This can't be happening.","TWN":"不，不可能，怎麼會……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"인류가 힘겹게 쌓아 올린 제7 방위선이 이렇게나 허무하게.","JPN":"人類が苦闘の末に築き上げた第7防衛線が、こんなにも虚しく。","ENG":"The 7th Defense Line that we worked so hard to build can't go down like this.","TWN":"人類費盡力氣建造的第七防線怎麼會如此不堪一擊…"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"모두, 모두 나 때문이야.","JPN":"全部、全部私のせいだ。","ENG":"It's... It's all my fault.","TWN":"全部……都是因為我。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨, 사이버캣 그리고 다른 대원들 모두 나 때문에.","JPN":"シノンさん、サイバーキャット、そして他の隊員のみんなが私のせいで。","ENG":"It's my fault for what happened to Shiyoung, Cyber Cat, and all the other troops.","TWN":"時雨，賽博貓還有其他隊員們，都是因為我才…"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흑, 흐흑……!","JPN":"う……うう……っ！","ENG":"*Sniffle* Hnnggg...!","TWN":"嗚，嗚嗚……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님, 이제 저는 어떻게 해야……!","JPN":"大佐、私はこれからどうすれば……！","ENG":"Colonel, what am I supposed to do...?","TWN":"上校，我現在該怎麼辦……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 소리는……?","JPN":"今の音は……？","ENG":"What's that sound...?","TWN":"有聲音……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"누군가 있어! 아직 누군가 살릴 수 있을 지도 몰라!","JPN":"誰かいる！　まだ誰か助けられる人がいるのかもしれないわ！","ENG":"Someone's here! There's still someone I can save!","TWN":"有人！也許還有人活著！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"피터, 피터 대원! 정신 차리세요, 피터 대원!","JPN":"ピーター、ピーター隊員！　しっかり、ピーター隊員！","ENG":"Peter, Peter! Wake up, Peter!","TWN":"彼得，彼得隊員！醒醒，彼得！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"소…… 령님?","JPN":"しょ、小……佐？","ENG":"Maj... or?","TWN":"少……校？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그래요, 저예요! 안심하세요! 제가 왔으니 살 수 있어요!","JPN":"はい、私です！　もう安心してください！　私が助けに来ましたから！","ENG":"Yes, it's me! Don't worry! I'm here to save you!","TWN":"對，是我！放心吧！我來了，你會沒事的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"저, 저를…….","JPN":"ぼ、僕を……","ENG":"P-please...","TWN":"我，我……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"주, 죽여…… 주세요. 소령…… 님.","JPN":"こ、殺して……ください。少佐……","ENG":"K-kill me, M-Major...","TWN":"請，請殺了……我。少校……。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"예?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"침식 쐐기에 너무 깊게 찔려버려서……","JPN":"侵食楔が深く刺さりすぎて……","ENG":"The Corrupted Wedge... It stabbed me too deeply...","TWN":"侵蝕釘扎的太深了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"아, 아파……!! 너무 아파서……!!","JPN":"い、痛い……！！　すごく痛くて……！！","ENG":"I-it hurts...!! It hurts so much...!!","TWN":"痛，我好痛……！！真的太痛……！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"으아, 아아아아아악!!","JPN":"ああ、ああああああ！！","ENG":"Agh, AAAAGH!!","TWN":"呃啊，啊啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_METAMOR_02"},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"침착하세요, 피터! 포기하면 안 됩니다! 포기하면!!","JPN":"落ち着いてください、ピーター！　諦めてはいけません！　頑張って！！","ENG":"Calm down, Peter! You can't give up! Stay with–!!","TWN":"保持冷靜，彼得！不能放棄！這麼放棄的話！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"무, 무슨 짓이죠? 행정관?","JPN":"な、なにをするのですか？　行政官？","ENG":"Officer Antonov, w-why did you do that?","TWN":"你，你在做什麼？行政官？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"알고 있을 텐데, 소령. 쐐기에 몸을 관통당했네.","JPN":"わかっているだろう、少佐。楔が身体を貫いたんだ。","ENG":"I'm sure you know why, Major. He was impaled by the Wedge.","TWN":"你應該很清楚，少校。他的身體已經被侵蝕釘穿透了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"운 좋게 살아봤자, 급성 침식 증후군으로 인해 얼마 안 가 침식체가 되어버리겠지.","JPN":"運よく助かっても、そのうち急性侵食症候群によって侵食体になってしまうだろう。","ENG":"Even if he somehow makes it through, he'll turn into a C.O. soon due to the acute Corruption Syndrome.","TWN":"就算運氣好活下來，也會因急性侵蝕症候群，很快變成侵蝕體。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그리고 스스로의 의지와 관계없이 사람을 죽일 걸세.","JPN":"そして自らの意思とは無関係に、人々を殺戮することになる。","ENG":"Then, he'll have no control and start killing people.","TWN":"然後，他會控制不了自己的意識開始殺害人類。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이 세계가 끝나버리는 그 순간까지 계속.","JPN":"この世界が終わる瞬間まで、ずっとだ。","ENG":"And he won't stop until the day this world ends.","TWN":"直到這個世界徹底毀滅的那一刻為止。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신, 설마 기억이?","JPN":"あなた、まさか記憶が？","ENG":"Wait, are your memories...?","TWN":"安東諾夫行政官，你的記憶恢復了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그렇다고 하더라도 이래서는 앞서간 대원들을 볼 면목이…….","JPN":"で、ですが、これでは先立った隊員たちに面目が……","ENG":"B-but even so, I will be ashamed to face the other troops who fell before me...","TWN":"即，即便如此，我拿什麼面對那些犧牲的隊員們……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"착각하지 말게.","JPN":"勘違いしないでくれ。","ENG":"Don't be mistaken.","TWN":"別搞錯了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리에게 필요한 건 죽은 자에 대한 추모나 감상 따위가 아니야.","JPN":"我々に必要なのは死者への弔いでも、感傷でもない。","ENG":"We do not need respect or mourning for the deceased at this time.","TWN":"我們需要的不是對亡者的追悼和感傷。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"필요한 건, 앞으로 더 많은 사람을 살리기 위한 실질적인 대책이지.","JPN":"必要なのは、この先少しでも多くの者を生かすための具体的な対策だ。","ENG":"We need an effective plan to save more lives in the years to come.","TWN":"我們需要的，是以後能讓更多人活下來的實際作為。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"실질적인 대책이라고?","JPN":"具体的な対策？","ENG":"An effective plan?","TWN":"實際作為？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"따라오게. 자네에게 한 가지 제안을 하고 싶군.","JPN":"ついてきてくれ。君に一つ提案がしたい。","ENG":"Follow me. I want to make you a proposition.","TWN":"跟我來。我有個提議。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"일단, 두 사람 다 급한 고비는 넘겼어.","JPN":"ひとまず、二人とも峠は越えたよ。","ENG":"For the time being, these two are over the hump.","TWN":"好了，她們二個都已經渡過危險期。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"응급치료는 해두었지만, 비위생적인 환경에서 수술을 시도한 건 자살 행위에 가까워.","JPN":"応急手当ては施したけど、非衛生的な環境下での手術は自殺行為に等しいんだ。","ENG":"I did some urgent care, but performing surgery in such an unsanitary environment was practically suicide.","TWN":"雖然做了應急治療，但在有菌環境下進一步進行手術無疑是自殺。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"당장 사령부 본부로 가서 정식으로 치료를 받아야 해.","JPN":"今すぐに司令本部に移送して、正式な治療を受けさせるべきだよ。","ENG":"They need to be transported to HQ and get proper medical treatment.","TWN":"需要馬上帶她們去司令總部接受正式的治療。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후, 비위생적인 환경이라 미안하군. 아무래도 꽤나 연식이 있는 배라서 말이지.","JPN":"ふふ、非衛生的な環境で申し訳ない。この艦船もだいぶ長く使っているからな。","ENG":"Ha ha, sorry about the unsanitary conditions. It's an old ship, after all.","TWN":"呵呵，非常抱歉。這艘船畢竟也有些年紀了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아, 아니 그런 뜻은 아니었는데…… 요.","JPN":"い、いや、そういうつもりで言ったわけじゃ……","ENG":"Oh, well, I didn't mean it like... that.","TWN":"不，不會，我不是那個……意思。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아이기스</color>, 항행 궤도 수정. 목표는 제1 지구 방위군 사령 본부.","JPN":"<color=#ffd34c>アイギス</color>、航行軌道を修正。目標は第1地区の防衛軍指令本部。","ENG":"<color=#ffd34c>Aegis</color>, correcting navigation trajectory. Destination: Defense Force HQ, 1st District.","TWN":"<color=#ffd34c>埃癸斯</color>，調整航行軌道。目的地為第一區保衛軍司令總部。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 함선은 로스트 쉽……?","JPN":"この艦船は、ロストシップ……？","ENG":"This ship is the Lost Ship...?","TWN":"這艘艦船是失落艦船……？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잠깐, 이 함선 오퍼레이터 없이 자동으로 항행하고 있잖아? 이런 게 가능할 리가?","JPN":"待って、この艦船、オペレーターがいないのに自動で航行しているの？　こんなの可能なわけ……？","ENG":"Wait, it's auto-piloting without any operators. How's that even possible?","TWN":"等等，這艘艦船沒有領航員，正在自動航行？怎麼可能？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"고성능 인공지능이라도 탑재되어 있는 건가?","JPN":"高性能人工知能でも搭載されているというの？","ENG":"Is it equipped with a high-performance AI?","TWN":"是搭載了高性能的人工智慧嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"글쎄? 단순한 인공지능이었다면 실비아가 눈치 채지 못할 리 없잖나.","JPN":"どうかな、単なる人工知能ならシルビアが気づかないわけがないと思うが？","ENG":"Take a guess. If it were just an AI, Sylvia would've already caught wind of it.","TWN":"是嗎？單單只是人工智慧的話，希爾維亞怎麼可能會察覺不到？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신, 사이버캣의 본명을?","JPN":"あなた、どうやってサイバーキャットの本名を？","ENG":"Huh? How do you know Cyber Cat's real name?","TWN":"你，你怎麼知道賽博貓的本名?"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"무엇보다도 나는 인공지능을 그다지 신뢰하지 않아서 말이지.","JPN":"何より、私はあまり人工知能を信頼しないのでね。","ENG":"But above all, I do not trust AIs that much.","TWN":"主要是我並不太信任人工智慧。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"간단히 말하자면 이 함선, 아이기스는 나와 직접적으로 연결되어 있다네.","JPN":"簡単に説明すると、この艦船、アイギスは私と直に繋がっているのだ。","ENG":"Simply put, this ship, Aegis, is directly connected to me.","TWN":"簡單說，埃癸斯這艘艦船和我的意識共通。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"함장인 내가 죽으면 모든 시스템이 영구 동결되고, 아이기스 무기고의 장비들은 분자 단위로 파기되도록 설정되어 있지.","JPN":"艦長である私が死ねばすべてのシステムは永久に凍結され、アイギスの武器庫に積まれている装備は分子単位に分解されるよう設定されている。","ENG":"All systems will go into permanent lockdown if I, the captain, die. Also, all the gear in the arsenal will be dismantled to a molecular level.","TWN":"作為艦長的我要是死了，所有系統都會永久凍結，埃癸斯武器庫裡的裝備也會被分解為分子銷毀掉。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"연결되어 있다고? 분자단위로 파기? 대체 그게 무슨 뜻이죠?","JPN":"繋がっている？　分子単位に分解？　いったいどういう意味ですか？","ENG":"Connected? Dismantled to a molecular level? What does that even mean?","TWN":"意識共通？分解成分子？到底是什麼意思？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니, 그보다 안토노프 행정관, 당신은 대체 누구입니까?","JPN":"いいえ、それよりもアントノフ行政官、あなたはいったい誰なんですか？","ENG":"Above all, Officer Antonov, who are you really?","TWN":"不，安東諾夫行政官，你到底是誰？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 말도 안 되는 거대 함선과 무기들로 우리 세계에서 대체 무슨 짓을 할 작정이었죠?","JPN":"このとてつもない巨大艦船や武器を私たちの世界に持ち込んだ目的は何なんですか？","ENG":"What were you planning to do to our world with this ridiculously massive ship and its weapons?","TWN":"如此不可思議的巨型艦船和還有各式武器，你打算在我們世界裡做什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"한 번에 질문이 너무 많군.","JPN":"一気に質問しすぎだな。","ENG":"You're asking too many questions at once.","TWN":"你的問題太多了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그럼, 나도 한 가지 묻고 싶네만.","JPN":"では、私の方からも一つ尋ねたい。","ENG":"Then, let me ask you one.","TWN":"首先，讓我先問你一個問題吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이쪽 세계의 <color=#ffd34c>마리아 안토노프</color>는 이미 전사한 건가?","JPN":"こちらの世界の<color=#ffd34c>マリア・アントノフ</color>はすでに戦死しているのか？","ENG":"Is the <color=#ffd34c>Maria Antonov</color> of this world already deceased?","TWN":"這個世界的<color=#ffd34c>瑪麗亞·安東諾夫</color>已經戰死了嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"마리아 안토노프?","JPN":"マリア・アントノフ？","ENG":"Maria Antonov?","TWN":"瑪麗亞·安東諾夫？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그게 누구죠? 제가 아는 한, 그런 사람은 존재하지 않습니다.","JPN":"それは誰ですか？　私の知る限りでは、そんな人は存在しません。","ENG":"Who may that be? As far as I know, no one with that name exists.","TWN":"那是誰？據我所知，這個世界沒有這個人。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후, 그런가. 운명도 참 짓궂군.","JPN":"ふふ、そういうことか。運命とは実に皮肉なものだな。","ENG":"Ha ha, is that so? Fate can be so cruel.","TWN":"呵呵，是嗎？命運真是太討厭了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"대원들의 목숨과 맞바꿔 도달한 오랜 항해의 끝이……","JPN":"長い航海の中で、隊員たちの命と引き換えにたどり着いた先というのが……","ENG":"At the end of my long voyage, reached at the cost of the crew members' lives...","TWN":"隊員們用生命換來的，漫長航行的盡頭……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"대적자도, 세계를 구할 영웅도 없는 이 따위 나약한 세계였다니.","JPN":"敵対者も、世界を救う英雄もいない、こんな軟弱な世界だったとは。","ENG":"I'm met with such a weak world with no Antagonist and no heroes.","TWN":"竟是如此弱小世界，既沒有敵對者，也沒有拯救世界的英雄。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대적자? 그게 뭐죠?","JPN":"敵対者？　何ですか、それは？","ENG":"Antagonist? What's that?","TWN":"敵對者？那是什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아까부터 영문 모를 소리만 하지 말고, 말고 좀 더 알아듣게 설명하세요!","JPN":"さっきから訳のわからないことばかり言って、もう少しわかるように説明してください！","ENG":"Stop talking in codes and explain so I can understand!","TWN":"別老說些莫名其妙的話，請說得明白一點！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이 단말기의 수치를 읽어보겠나?","JPN":"この端末の数字を読んでみてくれ。","ENG":"Will you read the number displayed on this terminal?","TWN":"你有看到這個終端機上的數字嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"1.197315……? 뭔가요, 이 난잡한 숫자는?","JPN":"1.197315……？　この数字の羅列はいったい？","ENG":"1.197315...? What do all these numbers mean?","TWN":"1.197315……？這是什麼？這個錯亂的數字有什麼意義？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이 단말기는 일종의 <color=#ffd34c>측정기</color>라네.","JPN":"この端末は<color=#ffd34c>測定器</color>のようなものだ。","ENG":"This terminal is a kind of <color=#ffd34c>gauge</color>.","TWN":"這個終端機是一種<color=#ffd34c>測量儀</color>。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"침식파에 장기간 피폭된 토양을 검출하여, 파장을 분석, 해당 세계의 <color=#ffd34c>침식률</color>을 대략적인 수치로 표기해주지.","JPN":"侵食波に長期間晒され続けた土壌を検出し、波長を分析することで、その世界の<color=#ffd34c>侵食率</color>を大体の数字で表してくれる。","ENG":"It detects soil with long-term exposure to Corruption rays, analyzes the wavelength, and displays an approximate figure of the world's <color=#ffd34c>Corruption rate</color>.","TWN":"可以檢測被侵蝕波長時間輻射的土壤，然後通過分析波長，記錄該世界的<color=#ffd34c>侵蝕率</color>的大概數值。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"오차는 있지만, 1이 넘는 수치는 보통 이면세계의 토양에서나 검출돼.","JPN":"誤差はあるが、通常は1を超える数値は裏世界の土壌でしか検出されない。","ENG":"There is a margin of error, but any figure over 1 is normally detected in the soil of Counterside.","TWN":"雖然存在誤差，但超過1的數值，一般只會在異界的土壤中被檢測到。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이게 무슨 뜻인지 알겠나?","JPN":"どういう意味かわかるか？","ENG":"Do you understand what I am saying?","TWN":"知道這是什麼意思嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 말은…… 우리 세계가 이면세계와 동일하다는 뜻인가요?","JPN":"つまり……私たちの世界は裏世界と同じということですか？","ENG":"You mean to say... that our world is the same as Counterside?","TWN":"你的意思……是說我們的世界和異界一樣嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"헛소리하지 마세요! 우리 세계는 아직 멸망하지 않았습니다!","JPN":"ふざけないでください！　私たちの世界はまだ滅んではいません！","ENG":"Don't be ridiculous! Our world hasn't been destroyed yet!","TWN":"別胡說八道了！我們的世界還沒有滅亡！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"유감스럽지만 멸망하지 않은 세계가 이런 수치를 가리키는 이유는 한 가지뿐이야.","JPN":"残念だが、滅んでいない世界においてこのような数値が検出される理由は一つしかない。","ENG":"I am sorry to tell you, but there is only one reason why a world with a Corruption rate like this has not collapsed yet.","TWN":"很遺憾，未滅亡的世界會顯示這樣的數值，理由只有一種。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"원래 멸망했어야 하는 세계가, 어떤 이유로 멸망을 회피한 거지.","JPN":"本来滅ぶはずだった世界が、何らかの要因により滅びから免れた。","ENG":"The world that was originally supposed to collapse somehow avoided it.","TWN":"本該滅亡的世界，因為某種原因而躲過滅亡。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이쯤 되면, 자네도 짐작하는 바가 있겠지?","JPN":"ここまで話したからには、君にも心当たりがあるだろう？","ENG":"By now, you should have a rough idea as to why, no?","TWN":"說到這裡，你心裡也有數了吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어떤 이유? 설마 크로스로드 작전이?","JPN":"何らかの要因？　まさかクロスロード作戦が？","ENG":"Somehow? Could it have been Operation Crossroads?","TWN":"某種原因？難道是十字路口作戰？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 그 작전으로 인해, 우리 세계는 20년의 유예기간을 벌었습니다!","JPN":"しかし私たちはその作戦によって、20年間の猶予期間を得ただけです！","ENG":"But that operation bought us 20 years' worth of time!","TWN":"但那場作戰為我們世界爭取了20年的時間！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아니. 애초에 전제부터가 틀렸어.","JPN":"いや、そもそもの前提が間違っている。","ENG":"No, your premise was wrong from the start.","TWN":"不，從一開始就錯了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 20년이라는 형편 좋은 기준은 대체 뭘 근거로 세운 건가?","JPN":"その20年という都合の良い数字の根拠はいったい何なのだ？","ENG":"On what grounds did you conveniently decide it was 20 years?","TWN":"到底是以什麼標準來判斷這20年就是好的呢？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어, 저기 그건 일단 제가 분석한 고치의 부화 기간이긴 한데요…… 하, 하하.","JPN":"あっ、それは一応僕が分析した、繭の孵化にかかる期間なんですけど……は、はは。","ENG":"Well, I was the one who found out that it took that long for a cocoon to hatch... Ha, ha ha.","TWN":"呃，那個，首先是我分析出了繭的孵化期……哈，哈哈。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"결과가 확정된 세계에서 그 과정 같은 건 중요하지 않아.","JPN":"結果が確定してしまった世界では、もはや過程など意味を持たない。","ENG":"Process means nothing in a world where the outcome is fixed.","TWN":"對於結局已定的世界，過程並不重要。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"설령, 어느 날 갑자기 이곳에 초인이 떨어져서 고치들을 전부 토벌한다고 해도.","JPN":"たとえある日、ここにいきなり超人が降ってきて、繭をすべて討伐してくれたとしてもだ。","ENG":"Even if, one day, a superhuman just appeared in this world and exterminated all of the cocoons.","TWN":"就算是某天這個世界突然出現一個超人，消滅掉所有的繭。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"곧 그 초인조차 감당할 수 없는, 또 다른 형태의 멸망이 닥쳐올 뿐이겠지.","JPN":"すぐにその超人ですら太刀打ちできない、また別の形の滅亡の危機が訪れるだけだ。","ENG":"Destruction will come in a different form, one that even this superhuman cannot handle.","TWN":"滅亡也會馬上以連超人都無能為力的形態來到。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"침식률에 의한 인과결정은 무슨 억지를 쓰더라도 결과에 과정을 끼워 맞출 테니까.","JPN":"侵食率による因果決定においては、どう足掻いたとしても、過程は結果の辻褄合わせに過ぎない。","ENG":"Causality determined by Corruption rate will force the process to fit the outcome regardless of how.","TWN":"這是因侵蝕率而決定的因果關係，不管怎麼頑強抵抗，結果都不會改變。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"결과에 과정을……?","JPN":"過程が結果の辻褄合わせ……？","ENG":"Force the process to fit the outcome...?","TWN":"結果……？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네들은 지난 크로스로드 작전으로 한번 세계를 구했다고 했지?","JPN":"君たちは、以前のクロスロード作戦で一度世界を救ったと言ったな？","ENG":"You told me that you saved this world during Operation Crossroads, right?","TWN":"你之前告訴我，十字路口作戰拯救過一次這個世界吧？"},"stage":{"bg":"SS_CROSSLOAD_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 그렇기에, 자네들의 세계를 끝내기 위해 그 새하얀 그림자가 나타난 거야.","JPN":"しかし、だからこそ君たちの世界を終わらせるために、あの真っ白なシャドウが現れたんだ。","ENG":"Because of that, the white Shadow has appeared to finish this world.","TWN":"但也因此，為了毀滅你們的世界，出現了白色暗影。"},"stage":{"bg":"SS_CROSSLOAD_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"기적과 기적이 겹쳐, 끝내 그 새하얀 그림자를 쓰러트린다고 해도.","JPN":"奇跡に奇跡が重なって、最終的にあの真っ白なシャドウを倒すことができたとしても。","ENG":"Even if by some miracle, you do defeat the white Shadow...","TWN":"哪怕奇蹟再次出現，最後打敗了那個白色暗影。"},"stage":{"bg":"SS_CROSSLOAD_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 뒤를 기다리고 있는 건 희망 같은 게 아니야. 또 다른 형태의 절망일 뿐이지.","JPN":"その先に待っているものは決して希望などではない。また違った形の絶望があるのみだ。","ENG":"What lies beyond is not hope. It will be despair in a different form.","TWN":"那之後等待你們的也不會是希望，而是另一種形態的絕望。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……웃기지 마.","JPN":"……ふざけないで。","ENG":"...That is absurd.","TWN":"……別開玩笑了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"소, 소령?","JPN":"しょ、少佐？","ENG":"M-Major?","TWN":"少，少校？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"목숨을 건 그때의 작전이, 대원들의 숭고한 희생이! 그들이 벌어준 소중한 시간이!","JPN":"命を賭けたあの時の作戦が、隊員たちの崇高なる犠牲が！　彼らが稼いでくれた大切な時間が！","ENG":"The operation where we risked our lives, the soldiers' noble sacrifices! The precious time they bought us!!","TWN":"那場賭上性命的作戰，隊員們崇高的犧牲！還有他們爭取來的寶貴時間！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어차피 처음부터 멸망이란 걸 피할 수 없는 거니까, 전부 무가치한 발버둥이었다고!?","JPN":"結局滅亡することは最初から決まっているから、全部無駄な悪足掻きだったって言うの！？","ENG":"It was all in vain?! Because this world was doomed from the start?!","TWN":"因為無論如何都無法避免的滅亡，就全都淪為無謂的掙扎嗎？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"웃기지 마!! 당신이 뭘 안다고 그딴 소리를 하는 거야!!","JPN":"ふざけないでよ！！　あなたにどうしてそんなことが言えるの！！","ENG":"You're wrong!! You have no right to say any of that!!","TWN":"真可笑！！你憑什麼這樣說！！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리가 대체 몇 번이나 우리 세계를 구했다고 생각하나.","JPN":"我々が何度自分たちの世界を救ったかわかるか。","ENG":"How many times do you think we saved our world?","TWN":"你以為我們拯救過多少次我們的世界？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐라고?","JPN":"何ですって？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리 세계는 자네의 세계보다 훨씬 진보된 세계였네.","JPN":"我々の世界は、君たちの世界よりも遥かに進歩していた。","ENG":"Our world was far more advanced than yours is.","TWN":"我們的世界比你們的要先進發達許多。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리 대원들은 전원, 텔로미어를 조작해 노화를 늦춰 언제나 전성기인 육체로 싸웠고.","JPN":"隊員は全員、テロメアの操作によって老化を遅らせ、常に全盛期の肉体で戦うことができた。","ENG":"We altered our telomeres to slow the rate of aging, allowing us to fight in our prime physical condition.","TWN":"所有隊員都可以透過控制端粒來延緩衰老，始終以全盛期的身體參與戰鬥。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"닥치는 대로 이면세계를 뒤져 발견한 고유 무장들을 분석하고 복제해서 그와 대등한 화력의 전술 무장을 양산할 수 있었지.","JPN":"手当たり次第に裏世界を探索し、発見した数々の固有武装を分析、複製して、それと対等な火力を持つ戦術武装を量産することさえできた。","ENG":"We scoured Counterside for Unique Gear, which we analyzed and duplicated to mass-produce Tactical Gear of equal firepower.","TWN":"並且可以隨意探索異界，分析發現的專屬裝備，複製並量產與他火力相當的戰術裝備。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 우리 중 아무도 눈치채지 못했어.","JPN":"しかし、我々の世界の誰ひとりとして、気付ける者はいなかったのだ。","ENG":"But none of us ever sensed it coming.","TWN":"但我們當中沒有任何人意識到。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그런 짓을 하면…… 그 세계의 수준에 맞지 않는 기술력을 쓰면, 오히려 세계의 침식률을 끌어올리게 된다는 걸 말이야.","JPN":"そんなことをしてしまえば……自分たちの世界の技術レベルを超えるテクノロジーを使ってしまったら、むしろその世界の侵食率を引き上げてしまうということに。","ENG":"By doing so... By using technology too advanced for the world, it would increase the world's Corruption rate in return.","TWN":"這樣做的後果……使用與這個世界的水準不匹配的技術，反而會提高世界的侵蝕率。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"결국 우리는 세계를 구할수록, 몇 번이나 더 큰 절망에 마주할 수밖에 없었네.","JPN":"結局我々は世界を救えば救うほど、さらに大きな絶望に幾度となく直面するしかなかった。","ENG":"Ultimately, the more we saved our world, the more despair we were faced with time and time again.","TWN":"到最後，我們越是拯救世界，越會面臨更多更大的絕望。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"바로 지금 자네들의 세계처럼 말이지.","JPN":"まさに今の君たちの世界のようにだ。","ENG":"Just like what is happening to your world.","TWN":"就和你們的世界一樣。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그래서 도망친 건가, 결국.","JPN":"それで最後には逃げたというの。","ENG":"So you ultimately fled.","TWN":"所以你們就逃跑了嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그래. 꼴사납지만 그게 우리가 할 수 있는 최선이었으니까.","JPN":"そうだ。惨めではあるが我々が選べる最善だったからな。","ENG":"Correct. Although it leaves a bad taste in my mouth, it was the best we could do.","TWN":"沒錯。雖然有些難看，但那是我們所能做的上上策了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리 세계가 간신히 축적한 기술을 보존해, 다음 번 인류에게 전달하는 것.","JPN":"我々の世界が辛うじて蓄積した技術を、次の人類に伝えること。","ENG":"To transfer the technology we barely accumulated in our world to the next human race.","TWN":"保護我的世界好不容易累積下來的技術，傳達給下一批人類。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그것이 우리에게, 나에게 주어진 마지막 사명이네.","JPN":"それが我々に、私に与えられた最後の使命だ。","ENG":"That is the final mission that was given to me, and to us.","TWN":"這就是賦予我們，賦予我的最後使命。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇게 도착한 세계가 우리 세계였다는 뜻인가요?","JPN":"そうしてたどり着いたのが、こちらの世界だったというわけですか？","ENG":"And the world you arrived just happened to be ours?","TWN":"然後就碰巧來到了我們的世界？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그렇네.","JPN":"そうだ。","ENG":"Yes.","TWN":"是。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 안타깝게도 침식률이 이 정도까지 진행된 세계는 더는 회생 가능성이 없어.","JPN":"しかし残念ながら、侵食率がここまで上昇している世界はもはや助かる見込みがない。","ENG":"Unfortunately, this world is no longer recoverable, looking at how much the Corruption rate has already progressed.","TWN":"可惜的是，侵蝕率如此高的世界，不存在重生的可能性。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"발버둥 칠수록 더욱 더 깊은 절망의 늪에 빠질 뿐이겠지.","JPN":"足掻けば足掻くほど、より深い絶望の沼に沈んでいくだけだろう。","ENG":"The more you fight it, the deeper you will fall into the pit of despair.","TWN":"越是垂死掙扎，越會陷入更深的絕望泥沼。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그래서 다 포기하고 결과를 받아들이라고?","JPN":"だから、すべてを諦めて結果を受け入れろと？","ENG":"So you want us to just give up and accept it?","TWN":"所以你的意思是想讓我們放棄一切，接受這個結局?"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"침식률인지, 뭔지 때문에…… 운명은 바꿀 수 없으니까…….","JPN":"侵食率だか何だかのせいで……運命は変えられないから……","ENG":"Because fate can't be changed... because of this Corruption rate you keep talking about...?","TWN":"因為侵蝕率什麼的……因為命運無法被改變……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어차피 멸망이라는 건 막을 수 없으니까! 얌전히 죽는 걸 기다리라는 건가요?","JPN":"どうせ滅ぶ運命だから！　大人しく最期の瞬間を待てということですか？","ENG":"You want us to sit around and wait for our doom since there's no way to stop the collapse?!","TWN":"反正滅亡無法阻止！所以要乖乖等死嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"소령, 자네는 기지를 떠나기 전 기억을 잃은 내게 선택지를 주었지?","JPN":"少佐、君は基地を離れる前、記憶喪失の私に選択肢を与えてくれただろう？","ENG":"Major, you gave me, a person who lost her memories, a choice before you left base. Remember that?","TWN":"少校，你離開基地之前，給了失憶的我一個選擇吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그럼 이번에는 내가 자네에게 선택지를 주고 싶군.","JPN":"ならば今度は、私の方から君に選択肢を与えよう。","ENG":"Now, I want to offer you a choice.","TWN":"那麼這次，我想給你一個選擇。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"선택지?","JPN":"選択肢？","ENG":"A choice?","TWN":"選擇？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"수없이 분화한 평행세계 중에서 단 하나의 세계.","JPN":"無数に分岐している平行世界の中でたったひとつ。","ENG":"Of all the countless parallel universes, there is one world.","TWN":"在無數分化的平行世界中，僅有一個世界。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"세계의 침식률을 관리하는 <color=#ffd34c>관리국</color>이라는 기관이 존재하는 세계가 있다네.","JPN":"世界の侵食率を管理する<color=#ffd34c>管理局</color>という機関が存在する世界がある。","ENG":"A world where the Corruption rate is managed by an institution called <color=#ffd34c>the Administration</color>.","TWN":"存在管理世界侵蝕率的組織，該組織名為<color=#ffd34c>管理局</color>。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리의 최종 목적지는 원래 그곳이었지.","JPN":"我々の本来の最終目的地はそこだった。","ENG":"Our ultimate objective was to reach that world.","TWN":"原本是我們最終的目的地。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"관리국? 잠깐? 당신 방금 관리국이라고 했어?","JPN":"管理局？　待ってください。今管理局と言いましたか？","ENG":"The Administration? Wait a minute. Did you just say \\"the Administration?\\"","TWN":"管理局？等等？你剛剛說管理局？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이미 멸망이 확정된 이 세계에서는 아무것도 할 수 없고, 아무도 구할 수 없어.","JPN":"すでに滅亡が確定したこの世界では、手を打つことも、誰かを救うこともできない。","ENG":"In a world where destruction is determined, there is nothing you can do to save it or its people.","TWN":"在這個註定要滅亡的世界裡，什麼也做不了，什麼也拯救不了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어떤가, 소령? 나와 함께 관리국이 존재하는 세계로 나아가지 않겠나?","JPN":"どうだ、少佐？　私と共に管理局のある世界に行かないか？","ENG":"What will it be, Major? Will you join me and head to the world where the Administration exists?","TWN":"怎麼樣，少校？要和我一起前往管理局所在的世界嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};